import {takeNumberOnly, getSummary, USDollar, capFirstLetter, handleTooltip} from "../../utils/util"
import style from "./index.module.scss"
import template from './index.html'

export default class Mortgage extends HTMLElement {
  static localName = "huanlin-mortgage"
  result
  isFirstRender = true
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }

  // https://www.wikihow.com/Calculate-Mortgage-Payments
  monthlyPayment = ({ mortgage, downPayment, interestRate, year }) => {
    const rate = takeNumberOnly(interestRate, false);

    const decimalRate = rate / 10000;
    const monthlyInterestRate = decimalRate / 12;
    const totalMonths = year * 12;
    const upper =
      monthlyInterestRate * Math.pow(monthlyInterestRate + 1, totalMonths);
    const down = Math.pow(monthlyInterestRate + 1, totalMonths) - 1;

    const monthlyPayment = (mortgage - downPayment) * (upper / down);
    return {
      monthlyPayment,
      mortgage,
      downPayment,
      interestRate,
      year
    }
  };

  handleLoadDonutChartData = (result, totalDonut) => {
    clearTimeout(this.tdidLoadDonutData)
    this.tdidLoadDonutData = setTimeout(() => {
      const data = [{
        type: "Principle",
        value: Math.ceil(result.totalPrinciplePaid)
      }, {
        type: "Interest",
        value: result.totalInterestPaid
      }]
      totalDonut.setAttribute("data", JSON.stringify(data))
    })
  }

  chartToggleOnClick = e => {
    const btn = e.currentTarget
    const name = btn.getAttribute("name")
    const stackedBarChart = this.shadowRoot.querySelector("huanlin-stacked-bar-chart")
    const totalDonut = this.shadowRoot.querySelector("#total")
    if (name === "stacked-bar-chart") {
      totalDonut.classList.add("hide") 
      stackedBarChart.classList.remove("hide")
      btn.nextElementSibling.classList.remove("active")
      btn.classList.add("active")
    } else if (name === "donut-chart") {
      totalDonut.classList.remove("hide") 
      stackedBarChart.classList.add("hide")
      btn.classList.add("active")
      btn.previousElementSibling.classList.remove("active")
    }
  }

  handleChartToggle = () => {
    this.buttonList = Array.from(this.shadowRoot.querySelectorAll(".toggle-group button"))
    this.buttonList.forEach(btn => {
      btn.addEventListener("click", this.chartToggleOnClick)
    })
  }

  handleTableRender = (result) => {
    customElements.whenDefined("huanlin-table").then(() => {
      const table = this.shadowRoot.querySelector("huanlin-table")
      const column = Object.keys(result.stackedBarChartData[0]).map(k => ({label: capFirstLetter(k), name: k}))
      // const data = result.stackedBarChartData.map(d => {
      //   return {
      //     year: d.year,
      //     principle: USDollar.format(Math.floor(d.principle)),
      //     interest: USDollar.format(Math.floor(d.interest)),
      //     balance: USDollar.format(Math.floor(d.balance)),
      //   }
      // })
      table.column = column
      table.data = result.stackedBarChartData
    })
  }

  handleFormSubmit = e => {
    e.preventDefault()
    const data = new FormData(e.currentTarget);
    const values = {}
    for (const entry of data) {
      if (["mortgage", "down-payment"].includes(entry[0])) {
        values[entry[0]] = Number(entry[1].split(",").join(""))
      } else {
        values[entry[0]] = Number(entry[1])
      }
    }
    if (values["down-payment"] > values.mortgage) {
      alert("Down payment can't be bigger than mortgage")
      return
    }
    const summary = this.monthlyPayment({
      mortgage: values.mortgage,
      interestRate: Math.floor(values["interest-rate"] * 100),
      downPayment: values["down-payment"],
      year: values.years
    })
    const interestPaid = this.shadowRoot.querySelector("[name='total-interest']")
    const principalPaid = this.shadowRoot.querySelector("[name='total-principal']")
    const monthlyPayment = this.shadowRoot.querySelector("[name='monthly-payment']")
    const paidOffBy = this.shadowRoot.querySelector("[name='paid-off-by']")
    this.result = getSummary(summary)
    interestPaid.setAttribute("value", `${this.result.dollarTotalInterestPaid}`)
    principalPaid.setAttribute("value", `${this.result.dollarTotalPrinciplePaid}`)
    monthlyPayment.setAttribute("value", `${this.result.dollarPayment}`)
    paidOffBy.setAttribute("value", `${this.result.paidOffByWhen}`)
    const chartData = this.result.stackedBarChartData
    this.stackedBarChart.setAttribute("data", JSON.stringify(chartData))
    !this.isFirstRender && this.handleLoadDonutChartData(this.result, this.totalDonut) 
    this.isFirstRender = false

    this.handleTableRender(this.result)
  }
  willLoad = () => {
    handleTooltip(this)
    this.form = this.shadowRoot.querySelector("form")
    const button = this.shadowRoot.querySelector("button")
    this.stackedBarChart = this.shadowRoot.querySelector("huanlin-stacked-bar-chart")
    this.totalDonut = this.shadowRoot.querySelector("#total")
    this.form.addEventListener("submit", this.handleFormSubmit)
    this.handleChartToggle()
    this.observer = new IntersectionObserver(entries => {
      for (const entry of entries) {
        if (entry.target === this.stackedBarChart && entry.isIntersecting) {
          customElements.whenDefined("huanlin-stacked-bar-chart").then(() => {
            button.click()
          })
        } else if (entry.target === this.totalDonut && entry.isIntersecting) {
          customElements.whenDefined("huanlin-donut").then(() => {
            this.handleLoadDonutChartData(this.result, this.totalDonut) 
          })
        }
      }
    });
    this.observer.observe(this.stackedBarChart);
    this.observer.observe(this.totalDonut);

    this.totalDonut.addEventListener("app-mouseover", this.handleDonutMouseover)
    this.totalDonut.addEventListener("app-mouseout", this.handleDonutMouseout)
    this.totalDonut.addEventListener("app-mousemove", this.handleDonutMousemove)
  }
  handleDonutMouseover = e => {
    const {select, data: d, color, event} = e.detail
    this.tooltip.style.display = "flex"
    this.tooltip.classList.add("donut")
    event.target.style.opacity = 1
    select(this.tooltip)
      .transition()
      .duration(200)
      .style('opacity', 1)
    const year = this.tooltip.querySelector(".year")
    year.innerHTML = ""
    const dot = this.tooltip.querySelector(".dot")
    dot.style.background = color(d.data.type)
    const text = this.tooltip.querySelector(".text")
    text.innerHTML = `${d.data.type} ${USDollar.format(Math.floor(d.data.value))}`
  }
  handleDonutMouseout = e => {
    const {event, select} = e.detail
    event.target.style.opacity = .8
    select(this.tooltip).style('opacity', 0)
    select(this.tooltip).style('display', "none")
    this.tooltip.classList.remove("donut")
    this.tooltip.style.display = "none"
  }
  handleDonutMousemove = e => {
    const {select, event} = e.detail
    select(this.tooltip)
      .style('left', (event.clientX + 14) + 'px')
      .style('top', (event.clientY + 14) + 'px')
  }
  connectedCallback() {
    this.classList.add("hydrated")
    clearTimeout(this.otid)
    this.otid = setTimeout(() => {
      this.willLoad()
      this.render()
    }, 200)
  }
  disconnectedCallback() {
    this.buttonList?.forEach(btn => {
      btn.removeEventListener("click", this.chartToggleOnClick)
    })
    this.observer && this.observer.disconnect()
    if (this.totalDonut) {
      this.totalDonut.removeEventListener("app-mouseover", this.handleDonutMouseover)
      this.totalDonut.removeEventListener("app-mouseout", this.handleDonutMouseout)
      this.totalDonut.removeEventListener("app-mousemove", this.handleDonutMousemove)
    }
    this.form && this.form.removeEventListener("submit", this.handleFormSubmit)
  }

  render = () => {
  }
}
